#include <bits/stdc++.h>
using namespace std;

int countTriplets(int arr[], int n) {
    // Sort array to use two-pointer approach
    sort(arr, arr + n);

    int count = 0;
    // Fix the largest element and find pair
    for(int i = n-1; i >= 2; i--) {
        int left = 0;
        int right = i-1;

        // Use two pointers to find pairs
        while(left < right) {
            if(arr[left] + arr[right] == arr[i]) {
                count++;
                left++;
                right--;
            }
            else if(arr[left] + arr[right] < arr[i]) {
                left++;
            }
            else {
                right--;
            }
        }
    }
    return count;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;
        int arr[n];
        for(int i = 0; i < n; i++) {
            cin >> arr[i];
        }
        cout << countTriplets(arr, n) << endl;
    }
    return 0;
}
